// Minimum epoch considered a valid synced time.
// Derived from the build date so it automatically advances with each firmware build.
// __DATE__ format: "Mmm DD YYYY"
static time_t buildDateEpoch() {
  const char *d = __DATE__;
  int year = (d[7]-'0')*1000 + (d[8]-'0')*100 + (d[9]-'0')*10 + (d[10]-'0');
  int day  = (d[4]==' ' ? 0 : (d[4]-'0')) * 10 + (d[5]-'0');
  int mon  = 1;
  if      (d[0]=='J' && d[1]=='a') mon = 1;
  else if (d[0]=='F')               mon = 2;
  else if (d[0]=='M' && d[2]=='r') mon = 3;
  else if (d[0]=='A' && d[1]=='p') mon = 4;
  else if (d[0]=='M' && d[2]=='y') mon = 5;
  else if (d[0]=='J' && d[2]=='n') mon = 6;
  else if (d[0]=='J' && d[2]=='l') mon = 7;
  else if (d[0]=='A' && d[1]=='u') mon = 8;
  else if (d[0]=='S')               mon = 9;
  else if (d[0]=='O')               mon = 10;
  else if (d[0]=='N')               mon = 11;
  else                               mon = 12;
  struct tm t = {};
  t.tm_year = year - 1900;
  t.tm_mon  = mon - 1;
  t.tm_mday = day;
  t.tm_isdst = -1;
  time_t epoch = mktime(&t);
  // mktime uses local time; subtract UTC offset to get UTC epoch
  return (epoch > 0) ? epoch : (time_t)1741000000L; // fallback: March 2025
}
// Initialised once in setup() to avoid calling mktime at static-init time
static time_t MIN_VALID_EPOCH = 1741000000L;

