// ---------------------------------------------------------------------------
// Logging
// ---------------------------------------------------------------------------

void logLine(const char *msg) {
  char line[272];
  snprintf(line, sizeof(line), "[%10lu ms] %s", (unsigned long)millis(), msg);
  Serial.println(line);
  Serial0.println(line);
}

void logf(const char *fmt, ...) {
  char buf[224];
  va_list args;
  va_start(args, fmt);
  vsnprintf(buf, sizeof(buf), fmt, args);
  va_end(args);
  logLine(buf);
}

// ---------------------------------------------------------------------------
// RGB LED
// ---------------------------------------------------------------------------

void setRgbLed(uint8_t r, uint8_t g, uint8_t b) {
  if (RGB_LED_PIN < 0) return;
  neopixelWrite((uint8_t)RGB_LED_PIN, r, g, b);
}

void hueToRgb(uint16_t hue, uint8_t &r, uint8_t &g, uint8_t &b) {
  uint8_t seg = (uint8_t)(hue / 256U);
  uint8_t x   = (uint8_t)(hue % 256U);
  switch (seg) {
    case 0: r=255; g=x;   b=0;   break;
    case 1: r=255-x; g=255; b=0; break;
    case 2: r=0;   g=255; b=x;   break;
    case 3: r=0;   g=255-x; b=255; break;
    case 4: r=x;   g=0;   b=255; break;
    default:r=255; g=0;   b=255-x; break;
  }
}

void setSpectrumHue(uint16_t hue) {
  uint8_t r=0, g=0, b=0;
  hueToRgb(hue, r, g, b);
  r = (uint8_t)((r * RGB_LED_BRIGHTNESS) / 255U);
  g = (uint8_t)((g * RGB_LED_BRIGHTNESS) / 255U);
  b = (uint8_t)((b * RGB_LED_BRIGHTNESS) / 255U);
  setRgbLed(r, g, b);
}

void updateContinuousRgb() {
  if (RGB_LED_PIN < 0) return;
  uint32_t phaseMs = millis() % RGB_SPECTRUM_PERIOD_MS;
  uint16_t hue = (uint16_t)((phaseMs * 1536UL) / RGB_SPECTRUM_PERIOD_MS) % 1536U;
  setSpectrumHue(hue);
}

void runRgbSpectrum(uint32_t durationMs) {
  if (durationMs == 0 || RGB_LED_PIN < 0) return;
  uint32_t startMs = millis();
  while (millis() - startMs < durationMs) {
    uint32_t elapsed = millis() - startMs;
    uint16_t hue = (uint16_t)((elapsed * 1536UL) / durationMs) % 1536U;
    setSpectrumHue(hue);
    delay(RGB_LED_STEP_MS);
  }
  setRgbLed(0, 0, 0);
}

void initRgbLed() {
  logf("RGB init. dataPin=%d powerPin=%d", (int)RGB_LED_PIN, (int)RGB_LED_PWR_PIN);
  if (RGB_LED_PWR_PIN >= 0) {
    pinMode((uint8_t)RGB_LED_PWR_PIN, OUTPUT);
    digitalWrite((uint8_t)RGB_LED_PWR_PIN, RGB_LED_POWER_ON);
  }
  setRgbLed(0, 0, 0);
}

// ---------------------------------------------------------------------------
// Screen list
// ---------------------------------------------------------------------------

void buildScreenList() {
  screenCount = 0;
  if (ENABLE_WEATHER_SCREEN)  screenList[screenCount++] = SCREEN_WEATHER;
  if (ENABLE_MARKET_SCREEN)   screenList[screenCount++] = SCREEN_MARKET;
  if (ENABLE_THOUGHTS_SCREEN) screenList[screenCount++] = SCREEN_THOUGHT;
  if (ENABLE_FOCUS_SCREEN)    screenList[screenCount++] = SCREEN_FOCUS;
  if (ENABLE_PRAYER_SCREEN)   screenList[screenCount++] = SCREEN_PRAYER;
  if (ENABLE_NEWS_SCREEN)     screenList[screenCount++] = SCREEN_NEWS;
  if (screenCount == 0) {
    // Fallback: always show weather
    screenList[screenCount++] = SCREEN_WEATHER;
  }
  logf("Screen list built: %u screens", (unsigned)screenCount);
  for (uint8_t i = 0; i < screenCount; ++i) {
    logf("  screen[%u] = %u", (unsigned)i, (unsigned)screenList[i]);
  }
}

uint32_t getIntervalForScreen(uint8_t screenId) {
  switch (screenId) {
    case SCREEN_WEATHER: return WEATHER_SCREEN_INTERVAL_SEC;
    case SCREEN_MARKET:  return MARKET_SCREEN_INTERVAL_SEC;
    case SCREEN_THOUGHT: return THOUGHTS_SCREEN_INTERVAL_SEC;
    case SCREEN_FOCUS:   return FOCUS_SCREEN_INTERVAL_SEC;
    case SCREEN_PRAYER:  return PRAYER_SCREEN_INTERVAL_SEC;
    case SCREEN_NEWS:    return NEWS_SCREEN_INTERVAL_SEC;
    default:             return WEATHER_SCREEN_INTERVAL_SEC;
  }
}

