const char *wakeupCauseStr(esp_sleep_wakeup_cause_t cause) {
  switch (cause) {
    case ESP_SLEEP_WAKEUP_UNDEFINED: return "UNDEFINED";
    case ESP_SLEEP_WAKEUP_TIMER:     return "TIMER";
    case ESP_SLEEP_WAKEUP_EXT0:      return "EXT0";
    case ESP_SLEEP_WAKEUP_EXT1:      return "EXT1";
    case ESP_SLEEP_WAKEUP_TOUCHPAD:  return "TOUCHPAD";
    case ESP_SLEEP_WAKEUP_ULP:       return "ULP";
    case ESP_SLEEP_WAKEUP_GPIO:      return "GPIO";
    case ESP_SLEEP_WAKEUP_UART:      return "UART";
    default:                         return "OTHER";
  }
}

// Persist WiFi credentials to NVS so OTA-updated firmware (which has no
// compiled-in credentials) can still connect on subsequent boots.
static void saveWiFiCredsToNVS(const char* ssid, const char* password) {
  Preferences prefs;
  prefs.begin("wifi", false);
  prefs.putString("ssid", ssid);
  prefs.putString("pass", password);
  prefs.end();
}

static bool loadWiFiCredsFromNVS(String& ssid, String& password) {
  Preferences prefs;
  prefs.begin("wifi", true);
  ssid     = prefs.getString("ssid", "");
  password = prefs.getString("pass", "");
  prefs.end();
  return ssid.length() > 0;
}

bool connectWiFi() {
  if (WiFi.status() == WL_CONNECTED) {
    logf("Wi-Fi already connected. IP=%s RSSI=%d dBm",
         WiFi.localIP().toString().c_str(), WiFi.RSSI());
    return true;
  }

  // Determine which credentials to use.
  // If compiled-in creds are real, use them and persist to NVS for future
  // OTA-updated firmware that won't have creds compiled in.
  String ssid, password;
  const bool compiledCreds = (strcmp(WIFI_SSID, "YOUR_WIFI_SSID") != 0);
  if (compiledCreds) {
    ssid     = WIFI_SSID;
    password = WIFI_PASSWORD;
    saveWiFiCredsToNVS(WIFI_SSID, WIFI_PASSWORD);
    logf("Wi-Fi: using compiled-in creds, saved to NVS. SSID='%s'", ssid.c_str());
  } else if (loadWiFiCredsFromNVS(ssid, password)) {
    logf("Wi-Fi: using NVS creds. SSID='%s'", ssid.c_str());
  } else {
    logf("Wi-Fi: no credentials available (no compiled-in, no NVS). Skipping.");
    return false;
  }

  logf("Wi-Fi connect start. SSID='%s'", ssid.c_str());
  WiFi.mode(WIFI_STA);
  WiFi.begin(ssid.c_str(), password.c_str());

  const uint32_t started = millis();
  uint32_t lastLogMs = 0;
  while (WiFi.status() != WL_CONNECTED && millis() - started < WIFI_TIMEOUT_MS) {
    if ((millis() - lastLogMs) > 1000) {
      logf("Wi-Fi waiting... elapsed=%lu ms", (unsigned long)(millis() - started));
      lastLogMs = millis();
    }
    delay(250);
  }
  const bool ok = WiFi.status() == WL_CONNECTED;
  if (ok) {
    logf("Wi-Fi connected. IP=%s RSSI=%d dBm",
         WiFi.localIP().toString().c_str(), WiFi.RSSI());
  } else {
    logf("Wi-Fi connect timeout after %lu ms", (unsigned long)(millis() - started));
  }
  return ok;
}

void syncClock() {
  logf("NTP sync start. UTC offset=%d", UTC_OFFSET_SECONDS);
  configTime(UTC_OFFSET_SECONDS, 0, "pool.ntp.org", "time.google.com", "time.nist.gov");

  time_t now = 0;
  const uint32_t started = millis();
  while (now < MIN_VALID_EPOCH && millis() - started < 15000) {
    time(&now);
    if (((millis() - started) % 2000) < 200) {
      logf("NTP waiting... now=%lld elapsed=%lu ms",
           (long long)now, (unsigned long)(millis() - started));
    }
    delay(200);
  }

  if (now > MIN_VALID_EPOCH) {
    struct tm timeinfo;
    localtime_r(&now, &timeinfo);
    char buf[32];
    strftime(buf, sizeof(buf), "%Y-%m-%d %H:%M:%S", &timeinfo);
    logf("NTP sync ok. Local: %s", buf);
  } else {
    logf("NTP sync failed after %lu ms", (unsigned long)(millis() - started));
  }
}

bool hasValidTime() {
  time_t now;
  time(&now);
  return now > MIN_VALID_EPOCH;
}

// ---------------------------------------------------------------------------
// HTTP helper with retry
// ---------------------------------------------------------------------------

bool httpGetRetry(const char *tag, const String &url, String &payload,
                  int &codeOut, int maxRetries = 3, const char *authToken = nullptr) {
  for (int attempt = 1; attempt <= maxRetries; ++attempt) {
    logf("%s attempt %d/%d URL: %s", tag, attempt, maxRetries, url.c_str());
    payload = "";
    codeOut = 0;

    WiFiClientSecure client;
    client.setInsecure();
    HTTPClient http;
    http.setTimeout(HTTP_TIMEOUT_MS);
    http.setFollowRedirects(HTTPC_FORCE_FOLLOW_REDIRECTS);
    if (!http.begin(client, url)) {
      logf("%s begin() failed", tag);
      if (attempt < maxRetries) { delay(1000 * attempt); continue; }
      return false;
    }
    http.addHeader("User-Agent", "EpaperDashboard/2.0");
    http.addHeader("Accept", "application/json");
    http.addHeader("Accept-Encoding", "identity");
    if (authToken && authToken[0] != '\0') {
      http.addHeader("Authorization", String("Bearer ") + authToken);
    }

    const int code = http.GET();
    codeOut = code;
    logf("%s HTTP %d", tag, code);

    if (code <= 0) {
      logf("%s transport error: %s", tag, http.errorToString(code).c_str());
      http.end();
      if (attempt < maxRetries) { delay(1000 * attempt); continue; }
      return false;
    }

    payload = http.getString();
    http.end();
    logf("%s payload bytes: %u", tag, (unsigned)payload.length());

    if (code != HTTP_CODE_OK) {
      logf("%s non-200: %d", tag, code);
      if (payload.length() > 0) {
        logf("%s error body: %s", tag, payload.substring(0, 160).c_str());
      }
      if (attempt < maxRetries) { delay(1000 * attempt); continue; }
      return false;
    }
    return true;
  }
  return false;
}

// ---------------------------------------------------------------------------
// Weather
// ---------------------------------------------------------------------------

void resetWeatherData(WeatherData &w) {
  w.valid = false;
  w.temperatureC = 0.0f;
  w.apparentTemperatureC = 0.0f;
  w.humidityPercent = 0.0f;
  w.uvIndex = -1.0f;
  w.rainChancePercent = -1;
  w.weatherCode = 65535;
}

bool fetchWeatherOpenMeteo(WeatherData &weather) {
  String url = "https://api.open-meteo.com/v1/forecast?latitude=";
  url += String(WEATHER_LATITUDE, 4);
  url += "&longitude=";
  url += String(WEATHER_LONGITUDE, 4);
  url += "&current=temperature_2m,apparent_temperature,weather_code,"
         "relative_humidity_2m,uv_index";
  url += "&hourly=precipitation_probability&forecast_days=1&timezone=auto";

  String payload;
  int code = 0;
  if (!httpGetRetry("Weather[OpenMeteo]", url, payload, code)) {
    return false;
  }

  JsonDocument doc;
  if (deserializeJson(doc, payload)) { return false; }

  JsonVariant current = doc["current"];
  if (current.isNull()) return false;

  weather.temperatureC         = current["temperature_2m"] | 0.0f;
  weather.apparentTemperatureC = current["apparent_temperature"] | 0.0f;
  weather.humidityPercent      = current["relative_humidity_2m"] | 0.0f;
  weather.uvIndex              = current["uv_index"] | -1.0f;
  weather.weatherCode          = (uint16_t)(current["weather_code"] | 65535);

  JsonVariant rainVal = doc["hourly"]["precipitation_probability"][0];
  if (!rainVal.isNull()) {
    int r = (int)(rainVal | -1);
    weather.rainChancePercent = (r < 0) ? -1 : (r > 100 ? 100 : r);
  }

  weather.valid = true;
  logf("Weather ok: %.1fC feels %.1fC hum %.0f%% uv %.1f rain %d%% code %u",
       weather.temperatureC, weather.apparentTemperatureC,
       weather.humidityPercent, weather.uvIndex,
       weather.rainChancePercent, (unsigned)weather.weatherCode);
  return true;
}

bool fetchWeather(WeatherData &weather) {
  resetWeatherData(weather);
  if (fetchWeatherOpenMeteo(weather)) return true;
  logLine("Weather fetch failed all providers");
  return false;
}

// Returns true if cached weather is still fresh
bool weatherCacheValid() {
  if (!cachedWeather.valid) return false;
  time_t now; time(&now);
  return (now - weatherFetchedAt) < WEATHER_CACHE_TTL_SEC;
}

// ---------------------------------------------------------------------------
// Thoughts
// ---------------------------------------------------------------------------

void normalizeThoughtText(const char *in, char *out, size_t outSize) {
  if (outSize == 0) return;
  size_t j = 0;
  bool prevSpace = true;
  for (size_t i = 0; in[i] != '\0' && j + 1 < outSize; ++i) {
    unsigned char c = (unsigned char)in[i];
    // Smart quotes and common Unicode punctuation -> ASCII equivalents
    if (c == 0xE2) {
      unsigned char c2 = (unsigned char)in[i+1];
      unsigned char c3 = (unsigned char)in[i+2];
      if (c2 == 0x80) {
        if (c3 == 0x98 || c3 == 0x99) { out[j++] = '\''; i += 2; prevSpace = false; continue; }
        if (c3 == 0x9C || c3 == 0x9D) { out[j++] = '"';  i += 2; prevSpace = false; continue; }
        if (c3 == 0x93 || c3 == 0x94) { out[j++] = '"';  i += 2; prevSpace = false; continue; }
        if (c3 == 0x94 || c3 == 0x95) { out[j++] = '-';  i += 2; prevSpace = false; continue; }
        if (c3 == 0xA6)               { out[j++] = '.';  out[j++] = '.'; out[j++] = '.'; i += 2; prevSpace = false; continue; }
      }
      // skip other multi-byte sequences
      if ((c2 & 0xC0) == 0x80) { i++; continue; }
      if ((c3 & 0xC0) == 0x80) { i += 2; continue; }
      continue;
    }
    char ch = (char)c;
    if (ch == '\r' || ch == '\n' || ch == '\t') ch = ' ';
    if (c < 32) continue;
    if (c > 126) continue; // drop remaining non-ASCII
    if (ch == ' ') {
      if (prevSpace) continue;
      prevSpace = true;
    } else {
      prevSpace = false;
    }
    out[j++] = ch;
  }
  while (j > 0 && out[j-1] == ' ') --j;
  out[j] = '\0';
}

void setClassicalThought(ThoughtData &thought, bool clockValid) {
  static const struct { const char *text; const char *source; } kQuotes[] = {
    {"What you seek is seeking you.",                              "Rumi"},
    {"The wound is the place where the light enters you.",         "Rumi"},
    {"Let yourself be silently drawn by what you truly love.",     "Rumi"},
    {"Raise your words, not your voice.",                          "Rumi"},
    {"Love is the bridge between you and everything.",             "Rumi"},
    {"Yesterday I was clever, so I wanted to change the world.",   "Rumi"},
    {"Knowledge without action is wastefulness.",                  "Imam al-Ghazali"},
    {"Action without knowledge is foolishness.",                   "Imam al-Ghazali"},
    {"Patience turns hardship into wisdom.",                       "Imam al-Ghazali"},
  };
  constexpr size_t kCount = sizeof(kQuotes) / sizeof(kQuotes[0]);

  uint32_t seed = bootCount;
  if (clockValid) { time_t now; time(&now); seed += (uint32_t)(now / 3600); }
  const size_t idx = seed % kCount;
  strncpy(thought.text,   kQuotes[idx].text,   sizeof(thought.text)   - 1);
  strncpy(thought.source, kQuotes[idx].source, sizeof(thought.source) - 1);
  thought.text[sizeof(thought.text)-1]     = '\0';
  thought.source[sizeof(thought.source)-1] = '\0';
  thought.valid    = true;
  thought.error[0] = '\0';
}

bool fetchShowerThought(ThoughtData &thought) {
  memset(&thought, 0, sizeof(thought));
  const String url = "https://www.reddit.com/r/Showerthoughts/top.json?t=day&limit=25";

  String payload;
  int code = 0;
  if (!httpGetRetry("Thought[Reddit]", url, payload, code)) {
    snprintf(thought.error, sizeof(thought.error), "HTTP %d", code);
    return false;
  }

  JsonDocument doc;
  if (deserializeJson(doc, payload)) {
    strncpy(thought.error, "JSON parse error", sizeof(thought.error)-1);
    return false;
  }

  JsonArray children = doc["data"]["children"];
  if (children.isNull() || children.size() == 0) {
    strncpy(thought.error, "no posts", sizeof(thought.error)-1);
    return false;
  }

  for (JsonObject child : children) {
    JsonObject post = child["data"];
    if (post.isNull()) continue;
    if ((post["stickied"] | false) || (post["over_18"] | false)) continue;
    const char *title = post["title"] | "";
    if (title[0] == '\0') continue;
    normalizeThoughtText(title, thought.text, sizeof(thought.text));
    if (strlen(thought.text) < 16) continue;
    strncpy(thought.source, "r/Showerthoughts", sizeof(thought.source)-1);
    thought.source[sizeof(thought.source)-1] = '\0';
    thought.valid    = true;
    thought.error[0] = '\0';
    return true;
  }
  strncpy(thought.error, "no suitable post", sizeof(thought.error)-1);
  return false;
}

void selectThought(ThoughtData &thought, bool wifiConnected, bool clockValid) {
  ThoughtData classical = {false,"","",""};
  setClassicalThought(classical, clockValid);

  if (!wifiConnected) { thought = classical; return; }

  ThoughtData reddit = {false,"","",""};
  const bool hasReddit = fetchShowerThought(reddit);
  if (!hasReddit) {
    thought = classical;
    strncpy(thought.error, reddit.error, sizeof(thought.error)-1);
    return;
  }
  thought = ((esp_random() & 1U) == 0U) ? reddit : classical;
}

// ---------------------------------------------------------------------------
// Market prices
// ---------------------------------------------------------------------------

void setMarketError(MarketData &market, const char *fmt, ...) {
  va_list args;
  va_start(args, fmt);
  vsnprintf(market.error, sizeof(market.error), fmt, args);
  va_end(args);
  logf("Market error: %s", market.error);
}

bool fetchMarketPrices(MarketData &market) {
  memset(&market, 0, sizeof(market));

  auto finalizeMarket = [&]() {
    market.hasZarUsd = market.zarUsd > 0.0f;
    market.hasZarMur = market.zarMur > 0.0f;
    market.valid = market.hasBtc || market.hasEth || market.hasGold || market.hasOil ||
                   market.hasZarUsd || market.hasZarMur;
  };

  // --- Yahoo Finance ---
  {
    const String url =
        "https://query1.finance.yahoo.com/v7/finance/quote?"
        "symbols=BTC-USD,ETH-USD,GC=F,CL=F,USDZAR=X,USDMUR=X";
    String payload; int code = 0;
    if (httpGetRetry("Market[Yahoo]", url, payload, code)) {
      JsonDocument doc;
      if (!deserializeJson(doc, payload)) {
        JsonArray results = doc["quoteResponse"]["result"];
        if (!results.isNull()) {
          float usdZar=0, usdMur=0; bool hasUsdZar=false, hasUsdMur=false;
          for (JsonObject q : results) {
            const char *sym = q["symbol"] | "";
            float price = q["regularMarketPrice"] | NAN;
            if (isnan(price)) continue;
            if      (strcmp(sym,"BTC-USD")==0)  { market.btcUsd=price; market.hasBtc=true; }
            else if (strcmp(sym,"ETH-USD")==0)  { market.ethUsd=price; market.hasEth=true; }
            else if (strcmp(sym,"GC=F")==0)     { market.goldUsd=price; market.hasGold=true; }
            else if (strcmp(sym,"CL=F")==0)     { market.oilUsd=price; market.hasOil=true; }
            else if (strcmp(sym,"USDZAR=X")==0) { usdZar=price; hasUsdZar=true; }
            else if (strcmp(sym,"USDMUR=X")==0) { usdMur=price; hasUsdMur=true; }
          }
          if (hasUsdZar && usdZar>0) market.zarUsd = usdZar;
          if (hasUsdZar && hasUsdMur && usdZar>0) market.zarMur = usdMur / usdZar;
        }
      }
    }
  }

  // --- Binance crypto fallback ---
  auto fetchBinanceOne = [&](const char *tag, const char *sym, float &out, bool &flag) {
    if (flag) return;
    String url = "https://api.binance.com/api/v3/ticker/price?symbol=";
    url += sym;
    String payload; int code = 0;
    if (!httpGetRetry(tag, url, payload, code)) return;
    JsonDocument doc;
    if (deserializeJson(doc, payload)) return;
    float p = (float)atof(doc["price"] | "0");
    if (p > 0) { out = p; flag = true; }
  };
  fetchBinanceOne("Market[Binance][BTC]", "BTCUSDT", market.btcUsd, market.hasBtc);
  fetchBinanceOne("Market[Binance][ETH]", "ETHUSDT", market.ethUsd, market.hasEth);

  // --- ER-API forex fallback ---
  if (!market.hasZarUsd || !market.hasZarMur) {
    String payload; int code = 0;
    if (httpGetRetry("Market[ER-API]", "https://open.er-api.com/v6/latest/USD", payload, code)) {
      JsonDocument doc;
      if (!deserializeJson(doc, payload)) {
        float usdZar = doc["rates"]["ZAR"] | 0.0f;
        float usdMur = doc["rates"]["MUR"] | 0.0f;
        if (usdZar > 0) { market.zarUsd = usdZar; market.hasZarUsd = true; }
        if (usdZar > 0 && usdMur > 0) { market.zarMur = usdMur / usdZar; market.hasZarMur = true; }
      }
    }
  }

  // --- Stooq commodities fallback ---
  auto fetchStooqOne = [&](const char *tag, const char *sym, float &out, bool &flag) {
    if (flag) return;
    String url = "https://stooq.com/q/l/?s="; url += sym; url += "&f=sd2t2ohlcv&h&e=csv";
    String payload; int code = 0;
    if (!httpGetRetry(tag, url, payload, code)) return;
    int start = 0;
    while (start < (int)payload.length()) {
      int end = payload.indexOf('\n', start);
      if (end < 0) end = payload.length();
      String line = payload.substring(start, end);
      line.trim(); start = end + 1;
      if (line.length() == 0 || line.startsWith("Symbol")) continue;
      String fields[8]; int fi = 0, p = 0;
      while (fi < 8) {
        int c = line.indexOf(',', p);
        if (c < 0) { fields[fi++] = line.substring(p); break; }
        fields[fi++] = line.substring(p, c); p = c + 1;
      }
      if (fi < 7) continue;
      float closePrice = fields[6].toFloat();
      if (closePrice <= 0) closePrice = fields[3].toFloat();
      if (closePrice > 0) { out = closePrice; flag = true; return; }
    }
  };
  fetchStooqOne("Market[Stooq][Gold]", "gc.f", market.goldUsd, market.hasGold);
  fetchStooqOne("Market[Stooq][Oil]",  "cl.f", market.oilUsd,  market.hasOil);

  finalizeMarket();
  if (market.valid) {
    market.error[0] = '\0';
    logf("Market: BTC %.2f ETH %.2f Gold %.2f Oil %.2f USDZAR %.4f ZARMUR %.4f",
         market.btcUsd, market.ethUsd, market.goldUsd, market.oilUsd,
         market.zarUsd, market.zarMur);
  } else {
    setMarketError(market, "all providers failed");
  }
  return market.valid;
}

// ---------------------------------------------------------------------------
// Prayer times
// ---------------------------------------------------------------------------

bool fetchPrayerTimes(PrayerData &prayer) {
  memset(&prayer, 0, sizeof(prayer));

  time_t now; time(&now);
  char url[256];
  snprintf(url, sizeof(url),
    "https://api.aladhan.com/v1/timings/%lld?latitude=%.4f&longitude=%.4f&method=%d",
    (long long)now, (double)WEATHER_LATITUDE, (double)WEATHER_LONGITUDE,
    PRAYER_CALC_METHOD);

  String payload; int code = 0;
  if (!httpGetRetry("Prayer[Aladhan]", String(url), payload, code)) {
    snprintf(prayer.error, sizeof(prayer.error), "HTTP %d", code);
    return false;
  }

  JsonDocument doc;
  if (deserializeJson(doc, payload)) {
    strncpy(prayer.error, "JSON parse error", sizeof(prayer.error)-1);
    return false;
  }

  JsonVariant timings = doc["data"]["timings"];
  if (timings.isNull()) {
    strncpy(prayer.error, "missing timings", sizeof(prayer.error)-1);
    return false;
  }

  auto copyTime = [](const char *src, char *dst, size_t n) {
    strncpy(dst, src, n-1); dst[n-1] = '\0';
    // Strip timezone suffix like " (SAST)" if present
    char *paren = strchr(dst, ' ');
    if (paren) *paren = '\0';
  };

  copyTime(timings["Fajr"]    | "", prayer.fajr,    sizeof(prayer.fajr));
  copyTime(timings["Dhuhr"]   | "", prayer.dhuhr,   sizeof(prayer.dhuhr));
  copyTime(timings["Asr"]     | "", prayer.asr,     sizeof(prayer.asr));
  copyTime(timings["Maghrib"] | "", prayer.maghrib, sizeof(prayer.maghrib));
  copyTime(timings["Isha"]    | "", prayer.isha,    sizeof(prayer.isha));

  struct tm timeinfo; localtime_r(&now, &timeinfo);
  strftime(prayer.date, sizeof(prayer.date), "%d %b %Y", &timeinfo);

  prayer.valid = true;
  logf("Prayer: Fajr=%s Dhuhr=%s Asr=%s Maghrib=%s Isha=%s",
       prayer.fajr, prayer.dhuhr, prayer.asr, prayer.maghrib, prayer.isha);
  return true;
}

// Returns true if cached prayer is still for today
bool prayerCacheValid() {
  if (!cachedPrayer.valid) return false;
  time_t now; time(&now);
  struct tm tm_now; localtime_r(&now, &tm_now);
  struct tm tm_fetched; localtime_r(&prayerFetchedDay, &tm_fetched);
  return (tm_now.tm_year == tm_fetched.tm_year &&
          tm_now.tm_yday == tm_fetched.tm_yday);
}

// ---------------------------------------------------------------------------
// News / HackerNews
// ---------------------------------------------------------------------------

bool fetchNewsHeadline(NewsData &news) {
  memset(&news, 0, sizeof(news));

  // HackerNews Algolia front-page search (no API key needed)
  const String url =
      "https://hn.algolia.com/api/v1/search?tags=front_page&hitsPerPage=10";

  String payload; int code = 0;
  if (!httpGetRetry("News[HN]", url, payload, code)) {
    snprintf(news.error, sizeof(news.error), "HTTP %d", code);
    return false;
  }

  JsonDocument doc;
  if (deserializeJson(doc, payload)) {
    strncpy(news.error, "JSON parse error", sizeof(news.error)-1);
    return false;
  }

  JsonArray hits = doc["hits"];
  if (hits.isNull() || hits.size() == 0) {
    strncpy(news.error, "no hits", sizeof(news.error)-1);
    return false;
  }

  // Pick first hit with a non-empty title
  for (JsonObject hit : hits) {
    const char *title = hit["title"] | "";
    if (title[0] == '\0') continue;
    normalizeThoughtText(title, news.headline, sizeof(news.headline));
    if (strlen(news.headline) < 8) continue;

    int points = hit["points"] | 0;
    if (points >= 1000) {
      snprintf(news.score, sizeof(news.score), "%.1fk pts", points / 1000.0f);
    } else {
      snprintf(news.score, sizeof(news.score), "%d pts", points);
    }

    // Extract domain from url for attribution
    const char *storyUrl = hit["url"] | "";
    strncpy(news.source, "Hacker News", sizeof(news.source)-1);
    if (storyUrl[0] != '\0') {
      // Find domain: skip https://  then take until next /
      const char *domStart = strstr(storyUrl, "://");
      if (domStart) {
        domStart += 3;
        const char *domEnd = strchr(domStart, '/');
        size_t len = domEnd ? (size_t)(domEnd - domStart) : strlen(domStart);
        // Skip www.
        if (strncmp(domStart, "www.", 4) == 0) { domStart += 4; len -= 4; }
        if (len > 0 && len < sizeof(news.source)-1) {
          strncpy(news.source, domStart, len);
          news.source[len] = '\0';
        }
      }
    }

    news.valid    = true;
    news.error[0] = '\0';
    logf("News: '%s' (%s, %s)", news.headline, news.source, news.score);
    return true;
  }

  strncpy(news.error, "no suitable story", sizeof(news.error)-1);
  return false;
}

// ---------------------------------------------------------------------------
// Moon phase
// ---------------------------------------------------------------------------

// Returns 0-7: 0=New, 1=WaxCrescent, 2=FirstQuarter, 3=WaxGibbous,
//              4=Full, 5=WanGibbous, 6=LastQuarter, 7=WanCrescent
uint8_t moonPhaseIndex(time_t t) {
  // Known new moon: Jan 6 2000 18:14 UTC = 947182440
  const double knownNewMoon = 947182440.0;
  const double synodicMonth = 29.53058867;
  double daysSince = (t - knownNewMoon) / 86400.0;
  double cycles = daysSince / synodicMonth;
  double phase = cycles - (long long)cycles; // fractional part [0,1)
  if (phase < 0) phase += 1.0;
  return (uint8_t)(phase * 8.0) % 8;
}

const char *moonPhaseName(uint8_t phase) {
  static const char *names[] = {
    "New", "Wax Crescent", "1st Qtr", "Wax Gibbous",
    "Full", "Wan Gibbous", "Last Qtr", "Wan Crescent"
  };
  return names[phase % 8];
}

void drawMoonPhase(int16_t cx, int16_t cy, uint8_t phase) {
  const int16_t r = 6;
  display.drawCircle(cx, cy, r, GxEPD_BLACK);
  switch (phase) {
    case 0: // New - empty circle (already drawn)
      break;
    case 4: // Full - filled
      display.fillCircle(cx, cy, r, GxEPD_BLACK);
      break;
    case 2: // First quarter - right half filled
      display.fillRect(cx, cy - r, r + 1, r * 2 + 1, GxEPD_BLACK);
      display.drawCircle(cx, cy, r, GxEPD_BLACK);
      break;
    case 6: // Last quarter - left half filled
      display.fillRect(cx - r, cy - r, r + 1, r * 2 + 1, GxEPD_BLACK);
      display.drawCircle(cx, cy, r, GxEPD_BLACK);
      break;
    case 1: // Waxing crescent - thin right sliver
      display.fillRect(cx + r/2, cy - r, r - r/2 + 1, r * 2 + 1, GxEPD_BLACK);
      display.drawCircle(cx, cy, r, GxEPD_BLACK);
      break;
    case 3: // Waxing gibbous - mostly right filled
      display.fillRect(cx - r/3, cy - r, r + r/3 + 1, r * 2 + 1, GxEPD_BLACK);
      display.drawCircle(cx, cy, r, GxEPD_BLACK);
      break;
    case 5: // Waning gibbous - mostly left filled
      display.fillRect(cx - r, cy - r, r + r/3 + 1, r * 2 + 1, GxEPD_BLACK);
      display.drawCircle(cx, cy, r, GxEPD_BLACK);
      break;
    case 7: // Waning crescent - thin left sliver
      display.fillRect(cx - r, cy - r, r - r/2 + 1, r * 2 + 1, GxEPD_BLACK);
      display.drawCircle(cx, cy, r, GxEPD_BLACK);
      break;
  }
}

// ---------------------------------------------------------------------------
// Weather icons
// ---------------------------------------------------------------------------

enum class WeatherIcon : uint8_t { Sun, Cloud, Rain, Storm, Snow, Fog, Unknown };

WeatherIcon iconFromWeatherCode(uint16_t code) {
  if (code <= 99) {
    if (code == 0)                                          return WeatherIcon::Sun;
    if (code <= 3)                                          return WeatherIcon::Cloud;
    if (code == 45 || code == 48)                           return WeatherIcon::Fog;
    if (code == 95 || code == 96 || code == 99)             return WeatherIcon::Storm;
    if (code==71||code==73||code==75||code==77||code==85||code==86) return WeatherIcon::Snow;
    if (code>=51&&code<=82)                                 return WeatherIcon::Rain;
    return WeatherIcon::Unknown;
  }
  if (code == 800)                    return WeatherIcon::Sun;
  if (code >= 801 && code <= 804)     return WeatherIcon::Cloud;
  if (code >= 701 && code <= 781)     return WeatherIcon::Fog;
  if (code >= 200 && code <= 232)     return WeatherIcon::Storm;
  if (code >= 600 && code <= 622)     return WeatherIcon::Snow;
  if (code >= 300 && code <= 531)     return WeatherIcon::Rain;
  return WeatherIcon::Unknown;
}

void drawSunIcon(int16_t x, int16_t y) {
  static const int8_t rays[8][2] = {{0,-5},{4,-4},{5,0},{4,4},{0,5},{-4,4},{-5,0},{-4,-4}};
  const int16_t cx = x+10, cy = y+9;
  display.drawCircle(cx, cy, 4, GxEPD_BLACK);
  display.fillCircle(cx, cy, 2, GxEPD_BLACK);
  for (uint8_t i=0; i<8; ++i)
    display.drawLine(cx+rays[i][0], cy+rays[i][1],
                     cx+(rays[i][0]*7)/5, cy+(rays[i][1]*7)/5, GxEPD_BLACK);
}

void drawCloudBase(int16_t x, int16_t y) {
  display.drawCircle(x+6,  y+10, 4, GxEPD_BLACK);
  display.drawCircle(x+11, y+8,  5, GxEPD_BLACK);
  display.drawCircle(x+16, y+10, 4, GxEPD_BLACK);
  display.drawRoundRect(x+4, y+10, 14, 6, 2, GxEPD_BLACK);
}

void drawRainIcon(int16_t x, int16_t y) {
  drawCloudBase(x, y);
  display.drawLine(x+7,  y+15, x+5,  y+18, GxEPD_BLACK);
  display.drawLine(x+11, y+15, x+9,  y+18, GxEPD_BLACK);
  display.drawLine(x+15, y+15, x+13, y+18, GxEPD_BLACK);
}

void drawStormIcon(int16_t x, int16_t y) {
  drawCloudBase(x, y);
  display.drawLine(x+10, y+14, x+8,  y+18, GxEPD_BLACK);
  display.drawLine(x+8,  y+18, x+12, y+18, GxEPD_BLACK);
  display.drawLine(x+12, y+18, x+10, y+22, GxEPD_BLACK);
}

void drawSnowIcon(int16_t x, int16_t y) {
  drawCloudBase(x, y);
  display.drawLine(x+8,  y+16, x+8,  y+20, GxEPD_BLACK);
  display.drawLine(x+6,  y+18, x+10, y+18, GxEPD_BLACK);
  display.drawLine(x+14, y+16, x+14, y+20, GxEPD_BLACK);
  display.drawLine(x+12, y+18, x+16, y+18, GxEPD_BLACK);
}

void drawFogIcon(int16_t x, int16_t y) {
  drawCloudBase(x, y-2);
  display.drawLine(x+4,  y+14, x+18, y+14, GxEPD_BLACK);
  display.drawLine(x+3,  y+17, x+17, y+17, GxEPD_BLACK);
}

void drawUnknownIcon(int16_t x, int16_t y) {
  display.drawCircle(x+11, y+10, 7, GxEPD_BLACK);
  display.drawLine(x+8, y+7, x+14, y+13, GxEPD_BLACK);
  display.drawLine(x+14, y+7, x+8, y+13, GxEPD_BLACK);
}

void drawWeatherIconAt(int16_t x, int16_t y, const WeatherData &weather) {
  if (!weather.valid) { drawUnknownIcon(x, y); return; }
  switch (iconFromWeatherCode(weather.weatherCode)) {
    case WeatherIcon::Sun:   drawSunIcon(x, y);   break;
    case WeatherIcon::Cloud: drawCloudBase(x, y); break;
    case WeatherIcon::Rain:  drawRainIcon(x, y);  break;
    case WeatherIcon::Storm: drawStormIcon(x, y); break;
    case WeatherIcon::Snow:  drawSnowIcon(x, y);  break;
    case WeatherIcon::Fog:   drawFogIcon(x, y);   break;
    default:                 drawUnknownIcon(x, y); break;
  }
}

