// ---------------------------------------------------------------------------
// Text wrap helper
// ---------------------------------------------------------------------------

void drawWrappedLineBlock(const char *text, int16_t x, int16_t y,
                          int16_t maxWidth, uint8_t maxLines, int16_t lineHeight) {
  String line = "", word = "";
  uint8_t linesUsed = 0;

  auto lineWidth = [](const String &s) -> uint16_t {
    int16_t x1, y1; uint16_t w, h;
    display.getTextBounds(s, 0, 0, &x1, &y1, &w, &h);
    return w;
  };

  auto flushLine = [&](const String &toPrint) -> bool {
    if (linesUsed >= maxLines) return false;
    display.setCursor(x, y + (int16_t)(linesUsed * lineHeight));
    display.print(toPrint);
    return ++linesUsed < maxLines;
  };

  const size_t len = strlen(text);
  for (size_t i = 0; i <= len; ++i) {
    const char c = (i < len) ? text[i] : ' ';
    const bool isBreak = (c==' ' || c=='\n' || i==len);
    if (!isBreak) { word += c; continue; }
    if (word.length() > 0) {
      String candidate = line.length() > 0 ? line + " " + word : word;
      if (lineWidth(candidate) <= (uint16_t)maxWidth) {
        line = candidate;
      } else {
        if (line.length() > 0) {
          if (!flushLine(line)) return;
          line = word;
        } else {
          String chunk = "";
          for (size_t j = 0; j < word.length(); ++j) {
            String test = chunk + word[j];
            if (lineWidth(test) <= (uint16_t)maxWidth) { chunk = test; }
            else { if (!flushLine(chunk)) return; chunk = String(word[j]); }
          }
          line = chunk;
        }
      }
      word = "";
    }
    if (c == '\n' && line.length() > 0) {
      if (!flushLine(line)) return;
      line = "";
    }
  }
  if (line.length() > 0 && linesUsed < maxLines) flushLine(line);
}

// ---------------------------------------------------------------------------
// Screen: Clock + Weather
// ---------------------------------------------------------------------------

void drawClockWeatherScreen(const WeatherData &weather, bool clockValid,
                            bool wifiConnected) {
  logf("Render weather screen. clockValid=%d weatherValid=%d", clockValid, weather.valid);
  display.setRotation(1);
  display.setFullWindow();

  char timeBuf[12]  = "--:--";
  char dateBuf[24]  = "No time sync";

  if (clockValid) {
    time_t now; time(&now);
    struct tm timeinfo; localtime_r(&now, &timeinfo);
    strftime(timeBuf, sizeof(timeBuf), "%H:%M", &timeinfo);
    strftime(dateBuf, sizeof(dateBuf), "%a %b %d", &timeinfo);
  }

  // Moon phase
  uint8_t moonPhase = 0;
  bool showMoon = false;
  if (clockValid) {
    time_t now; time(&now);
    moonPhase = moonPhaseIndex(now);
    showMoon = true;
  }

  display.firstPage();
  do {
    display.fillScreen(GxEPD_WHITE);
    drawHeaderBase("Clock + Weather");
    drawWeatherIconAt(273, 0, weather);

    display.setFont(&FreeMonoBold18pt7b);
    display.setCursor(8, 62);
    display.print(timeBuf);

    display.setFont(&FreeMono9pt7b);
    display.setCursor(8, 86);
    display.print(dateBuf);

    if (weather.valid) {
      display.setCursor(8, 102);
      display.printf("Temp %.1fC Feels %.1fC", weather.temperatureC,
                     weather.apparentTemperatureC);
      display.setCursor(8, 118);
      display.printf("Hum %.0f%% UV ", weather.humidityPercent);
      if (weather.uvIndex >= 0) display.print(weather.uvIndex, 1);
      else display.print("n/a");
      display.print(" Rain ");
      if (weather.rainChancePercent >= 0) {
        display.print(weather.rainChancePercent); display.print("%");
      } else {
        display.print("n/a");
      }
    } else {
      display.setCursor(8, 108);
      display.print("Weather unavailable");
      display.setCursor(8, 126);
      display.print(wifiConnected ? "API error" : "Wi-Fi disconnected");
    }

    // Moon phase in bottom-right
    if (showMoon) {
      drawMoonPhase(280, 110, moonPhase);
      display.setFont(&FreeMono9pt7b);
      // no text label — icon is self-explanatory
    }
  } while (display.nextPage());
}

// ---------------------------------------------------------------------------
// Screen: Market prices
// ---------------------------------------------------------------------------

void drawMarketScreen(const MarketData &market, bool clockValid,
                      bool wifiConnected, const WeatherData &weather) {
  logf("Render market screen. clockValid=%d marketValid=%d", clockValid, market.valid);
  display.setRotation(1);
  display.setFullWindow();

  auto drawTrendSuffix = [](bool hasCur, float cur, bool hasPrev, float prev, float thr) {
    if (!hasCur || !hasPrev) return;
    float delta = cur - prev;
    char trend = (delta > thr) ? '^' : (delta < -thr) ? 'v' : '=';
    display.print(" "); display.print(trend);
  };

  const bool hasPrev = lastMarketData.valid;
  display.firstPage();
  do {
    display.fillScreen(GxEPD_WHITE);
    drawHeaderBase("Markets (USD)");
    drawMarketIcon();
    display.setFont(&FreeMono9pt7b);
    drawHeaderClock(clockValid); // just prints time, title already drawn
    drawWeatherCorner(weather);

    if (market.valid) {
      display.setCursor(8, 36);
      if (market.hasBtc) {
        display.printf("BTC : $%.2f", market.btcUsd);
        drawTrendSuffix(market.hasBtc, market.btcUsd, lastMarketData.hasBtc, lastMarketData.btcUsd, 0.005f);
      } else display.print("BTC : n/a");

      display.setCursor(8, 50);
      if (market.hasEth) {
        display.printf("ETH : $%.2f", market.ethUsd);
        drawTrendSuffix(market.hasEth, market.ethUsd, lastMarketData.hasEth, lastMarketData.ethUsd, 0.005f);
      } else display.print("ETH : n/a");

      display.setCursor(8, 64);
      if (market.hasGold) {
        display.printf("Gold: $%.2f", market.goldUsd);
        drawTrendSuffix(market.hasGold, market.goldUsd, lastMarketData.hasGold, lastMarketData.goldUsd, 0.005f);
      } else display.print("Gold: n/a");

      display.setCursor(8, 78);
      if (market.hasOil) {
        display.printf("Oil : $%.2f", market.oilUsd);
        drawTrendSuffix(market.hasOil, market.oilUsd, lastMarketData.hasOil, lastMarketData.oilUsd, 0.005f);
      } else display.print("Oil : n/a");

      display.setCursor(8, 92);
      if (market.hasZarUsd) {
        display.printf("USD/ZAR: %.5f", market.zarUsd);
        drawTrendSuffix(market.hasZarUsd, market.zarUsd, lastMarketData.hasZarUsd, lastMarketData.zarUsd, 0.000005f);
      } else display.print("USD/ZAR: n/a");

      display.setCursor(8, 106);
      if (market.hasZarMur) {
        display.printf("ZAR/MUR: %.5f", market.zarMur);
        drawTrendSuffix(market.hasZarMur, market.zarMur, lastMarketData.hasZarMur, lastMarketData.zarMur, 0.000005f);
      } else display.print("ZAR/MUR: n/a");
    } else {
      display.setCursor(8, 72);
      display.print("Market data unavailable");
      display.setCursor(8, 94);
      if (!wifiConnected) display.print("Wi-Fi disconnected");
      else if (market.error[0] != '\0') display.print(market.error);
      else display.print("API error");
    }
  } while (display.nextPage());

  if (market.valid) {
    lastMarketData = market;
    lastMarketData.error[0] = '\0';
  }
}

