// Returns the optional GitHub token from config (nullptr if not set)
static const char *otaAuthToken() {
#ifdef OTA_GITHUB_TOKEN
  return OTA_GITHUB_TOKEN;
#else
  return nullptr;
#endif
}

bool fetchOtaVersionInfo(char *remoteSha, size_t shaSize, char *binaryUrl, size_t urlSize) {
  // version.json lives in the repo branch, served via raw.githubusercontent.com
  char url[256];
  snprintf(url, sizeof(url),
    "https://raw.githubusercontent.com/%s/%s/%s/version.json",
    OTA_REPO_OWNER, OTA_REPO_NAME, OTA_BRANCH);

  String payload; int code = 0;
  if (!httpGetRetry("OTA[version]", String(url), payload, code, 2, otaAuthToken())) {
    logf("OTA: version fetch failed (HTTP %d)", code);
    return false;
  }

  JsonDocument doc;
  if (deserializeJson(doc, payload)) {
    logLine("OTA: version.json parse error");
    return false;
  }

  const char *sha = doc["sha"] | "";
  const char *dlUrl = doc["url"] | "";

  if (sha[0] == '\0' || strcmp(sha, "none") == 0) {
    logLine("OTA: version.json has no valid SHA yet (CI not run?)");
    return false;
  }

  strncpy(remoteSha, sha,   shaSize  - 1); remoteSha[shaSize  - 1] = '\0';
  strncpy(binaryUrl, dlUrl, urlSize  - 1); binaryUrl[urlSize  - 1] = '\0';

  logf("OTA: remote SHA=%s url=%s", remoteSha, binaryUrl);
  return true;
}

bool streamOtaDownload(const char *binaryUrl) {
  logf("OTA: downloading from %s", binaryUrl);

  WiFiClientSecure client;
  client.setInsecure();
  HTTPClient http;
  http.setTimeout(HTTP_TIMEOUT_MS * 5); // firmware downloads take longer
  http.setFollowRedirects(HTTPC_FORCE_FOLLOW_REDIRECTS);
  if (!http.begin(client, binaryUrl)) {
    logLine("OTA: http.begin() failed for binary");
    return false;
  }
  http.addHeader("User-Agent", "EpaperDashboard/2.0");
  const char *tok = otaAuthToken();
  if (tok && tok[0] != '\0') {
    http.addHeader("Authorization", String("Bearer ") + tok);
  }
  // GitHub releases redirect to S3; the Accept header helps with API assets
  http.addHeader("Accept", "application/octet-stream");

  const int code = http.GET();
  if (code != HTTP_CODE_OK) {
    logf("OTA: binary download HTTP %d", code);
    http.end();
    return false;
  }

  const int contentLength = http.getSize();
  logf("OTA: binary size %d bytes", contentLength);

  if (!Update.begin(contentLength > 0 ? (size_t)contentLength : UPDATE_SIZE_UNKNOWN)) {
    logf("OTA: Update.begin failed. Free sketch space: %u", ESP.getFreeSketchSpace());
    http.end();
    Update.abort();
    return false;
  }

  WiFiClient *stream = http.getStreamPtr();
  uint8_t buf[512];
  size_t totalWritten = 0;
  uint32_t lastLog = millis();

  while (http.connected()) {
    size_t avail = stream->available();
    if (!avail) {
      if (contentLength > 0 && totalWritten >= (size_t)contentLength) break;
      delay(1);
      continue;
    }
    size_t toRead = min(avail, sizeof(buf));
    int n = stream->readBytes(buf, toRead);
    if (n > 0) {
      Update.write(buf, (size_t)n);
      totalWritten += (size_t)n;
    }
    if (millis() - lastLog > 3000) {
      logf("OTA: %u / %d bytes", (unsigned)totalWritten, contentLength);
      lastLog = millis();
    }
  }
  http.end();

  if (!Update.end()) {
    logf("OTA: Update.end() error: %s", Update.errorString());
    return false;
  }
  if (!Update.isFinished()) {
    logLine("OTA: Update.isFinished() false");
    return false;
  }

  logf("OTA: download complete, %u bytes written", (unsigned)totalWritten);
  return true;
}

// Returns true only if an OTA check is due.
// Checks on cold power-on boot and when midnight has been crossed since
// the last check, but never more often than OTA_CHECK_COOLDOWN_SEC.
bool shouldCheckForOta() {
  // Always check on cold boot (fresh power-on, not wake from deep sleep)
  const esp_sleep_wakeup_cause_t cause = esp_sleep_get_wakeup_cause();
  const bool isColdBoot = (cause == ESP_SLEEP_WAKEUP_UNDEFINED);

  time_t now; time(&now);
  if (!hasValidTime()) {
    // Without a valid clock we can still do the cold-boot check
    return isColdBoot && (lastOtaCheckTime == 0);
  }

  // Rate limit: never re-check within the cooldown window
  if (now - lastOtaCheckTime < OTA_CHECK_COOLDOWN_SEC) {
    return false;
  }

  if (isColdBoot) return true;

  // Midnight crossing: different calendar day since last check
  if (lastOtaCheckTime > 0) {
    struct tm tmNow;  localtime_r(&now,              &tmNow);
    struct tm tmLast; localtime_r(&lastOtaCheckTime, &tmLast);
    if (tmNow.tm_yday != tmLast.tm_yday || tmNow.tm_year != tmLast.tm_year) {
      return true;
    }
  } else {
    return true; // never checked before
  }

  return false;
}

void checkForFirmwareUpdate() {
  logLine("OTA: checking for update");

  char remoteSha[48]  = "";
  char binaryUrl[256] = "";

  if (!fetchOtaVersionInfo(remoteSha, sizeof(remoteSha), binaryUrl, sizeof(binaryUrl))) {
    logLine("OTA: could not fetch version info, skipping");
    // Still update the check timestamp so we don't hammer on every boot
    if (hasValidTime()) { time_t now; time(&now); lastOtaCheckTime = now; }
    return;
  }

  logf("OTA: local=%s remote=%s", FIRMWARE_SHA, remoteSha);

  if (strcmp(FIRMWARE_SHA, remoteSha) == 0) {
    logLine("OTA: firmware is up to date");
    if (hasValidTime()) { time_t now; time(&now); lastOtaCheckTime = now; }
    return;
  }

  if (binaryUrl[0] == '\0') {
    logLine("OTA: update available but no binary URL, skipping");
    if (hasValidTime()) { time_t now; time(&now); lastOtaCheckTime = now; }
    return;
  }

  // Show update screen BEFORE the long download
  char shaLine[64];
  snprintf(shaLine, sizeof(shaLine), "%s -> %s", FIRMWARE_SHA, remoteSha);
  drawOtaScreen("Downloading update...", shaLine);

  logf("OTA: starting download: %s", binaryUrl);
  const bool ok = streamOtaDownload(binaryUrl);

  if (ok) {
    logLine("OTA: success — restarting");
    drawOtaScreen("Update complete!", "Restarting...");
    // Reset screen list so buildScreenList() re-runs with new firmware's config
    screenCount = 0;
    delay(2000);
    esp_restart();
  } else {
    logLine("OTA: download/flash failed, continuing normal operation");
    drawOtaScreen("Update failed", "Continuing...");
    delay(2000);
    // Mark checked so we don't retry on every subsequent wake
    if (hasValidTime()) { time_t now; time(&now); lastOtaCheckTime = now; }
  }
}

// ---------------------------------------------------------------------------
// Main dashboard cycle
// ---------------------------------------------------------------------------

void runDashboardCycle(uint8_t screenId) {
  bool wifiConnected = false;
  bool clockValid    = false;

  WeatherData weather  = cachedWeather; // start with cached
  MarketData  market   = {false,false,false,false,false,false,false,0,0,0,0,0,0,""};
  ThoughtData thought  = {false,"","",""};
  PrayerData  prayer   = cachedPrayer;
  NewsData    news     = cachedNews;

  wifiConnected = connectWiFi();
  if (wifiConnected) {
    syncClock();
    clockValid = hasValidTime();

    // OTA check: runs on cold boot and midnight crossings.
    // If an update is found and flashed, esp_restart() is called inside
    // and this function never returns.
    if (shouldCheckForOta()) {
      checkForFirmwareUpdate();
    }

    // Fetch weather only if needed for this screen or cache is stale
    if (screenId == SCREEN_WEATHER || !weatherCacheValid()) {
      if (fetchWeather(weather)) {
        cachedWeather = weather;
        time_t now; time(&now); weatherFetchedAt = now;
      }
    }

    if (screenId == SCREEN_MARKET) {
      fetchMarketPrices(market);
    }
    if (screenId == SCREEN_THOUGHT) {
      selectThought(thought, true, clockValid);
    }
    if (screenId == SCREEN_PRAYER) {
      if (!prayerCacheValid()) {
        if (fetchPrayerTimes(prayer)) {
          cachedPrayer = prayer;
          time_t now; time(&now); prayerFetchedDay = now;
        }
      }
    }
    if (screenId == SCREEN_NEWS) {
      // Re-fetch news each time (headlines change frequently)
      if (fetchNewsHeadline(news)) {
        cachedNews = news;
      } else if (cachedNews.valid) {
        news = cachedNews; // use stale cache
      }
    }
  } else {
    // No Wi-Fi: use caches, fallback classical thought
    if (screenId == SCREEN_THOUGHT) {
      selectThought(thought, false, clockValid);
    }
  }

  const WeatherData &cornerWeather = cachedWeather;

  switch (screenId) {
    case SCREEN_WEATHER:
      drawClockWeatherScreen(weather, clockValid, wifiConnected);
      break;
    case SCREEN_MARKET:
      drawMarketScreen(market, clockValid, wifiConnected, cornerWeather);
      break;
    case SCREEN_THOUGHT:
      drawThoughtScreen(thought, clockValid, wifiConnected, cornerWeather);
      break;
    case SCREEN_FOCUS:
      drawFocusScreen(clockValid, cornerWeather);
      break;
    case SCREEN_PRAYER:
      drawPrayerScreen(prayer, clockValid, wifiConnected, cornerWeather);
      break;
    case SCREEN_NEWS:
      drawNewsScreen(news, clockValid, wifiConnected, cornerWeather);
      break;
    default:
      drawClockWeatherScreen(weather, clockValid, wifiConnected);
      break;
  }

  logf("Display updated for screenId=%u", (unsigned)screenId);
}

// ---------------------------------------------------------------------------
// Hardware setup + sleep
// ---------------------------------------------------------------------------

void setupDisplay() {
  logLine("Display init start");
  SPI.begin(EPD_SCK, -1, EPD_MOSI, EPD_CS);
  display.epd2.selectSPI(SPI, SPISettings(4000000, MSBFIRST, SPI_MODE0));
  display.init(115200, true, 2, false);
  logLine("Display init done");
}

void deepSleepUntilNextUpdate(uint32_t seconds) {
  logf("Deep sleep %u sec", (unsigned)seconds);
  setRgbLed(0, 0, 0);
  display.hibernate();
  WiFi.disconnect(true, true);
  WiFi.mode(WIFI_OFF);
  esp_sleep_enable_timer_wakeup((uint64_t)seconds * 1000000ULL);
  Serial.flush(); Serial0.flush();
  esp_deep_sleep_start();
}

// ---------------------------------------------------------------------------
// Arduino entry points
// ---------------------------------------------------------------------------

void setup() {
  // Build screen list on first boot (or if RTC was cleared)
  if (screenCount == 0) buildScreenList();

  const uint8_t screenId = screenList[bootCount % screenCount];
  ++bootCount;
  const esp_sleep_wakeup_cause_t wakeCause = esp_sleep_get_wakeup_cause();

  Serial.begin(115200);
  Serial0.begin(115200);
  MIN_VALID_EPOCH = buildDateEpoch();
  delay(SERIAL_WAIT_MS);

  logf("Boot #%lu screenId=%u wakeCause=%s",
       (unsigned long)(bootCount-1), (unsigned)screenId, wakeupCauseStr(wakeCause));
  logf("Build: %s %s  MIN_VALID_EPOCH=%lld",
       __DATE__, __TIME__, (long long)MIN_VALID_EPOCH);

  setupDisplay();
  initRgbLed();
  runDashboardCycle(screenId);

  if (CONTINUOUS_RGB_MODE) {
    continuousModeActive = true;
    activeCycle = bootCount % screenCount; // index into screenList for next render
    lastCycleRefreshMs = millis();
    logLine("Continuous RGB mode: staying awake");
    return;
  }

  runRgbSpectrum(POST_RENDER_LOG_MS);
  deepSleepUntilNextUpdate(getIntervalForScreen(screenId));
}

void loop() {
  if (!continuousModeActive) return;

  updateContinuousRgb();

  const uint8_t currentScreen = screenList[activeCycle % screenCount];
  const uint32_t refreshIntervalMs = getIntervalForScreen(currentScreen) * 1000UL;

  if (millis() - lastCycleRefreshMs >= refreshIntervalMs) {
    runDashboardCycle(currentScreen);
    ++bootCount;
    activeCycle = bootCount % screenCount;
    lastCycleRefreshMs = millis();
  }
  delay(RGB_LED_STEP_MS);
}
